#include <stdio.h>
#include <stdlib.h>

int popcnt(unsigned int x){
    return __builtin_popcount(x);
}

int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int N; unsigned int K; scanf("%d %u", &N, &K);
        unsigned int M = 1u << N;
        unsigned int printed = 0;
        for(unsigned int x=0; x<M && printed<K; ++x){
            unsigned int y = (x+1) & (M-1);
            unsigned int z = (x+2) & (M-1);
            if(popcnt(x) != popcnt(z)){
                printf("%u %u\n", x, y);
                ++printed;
            }
        }
    }
    return 0;
}

