import sys

def popcnt(x: int) -> int:
    return x.bit_count()

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        M = 1 << N
        printed = 0
        x = 0
        while printed < K and x < M:
            y = (x + 1) & (M - 1)
            z = (x + 2) & (M - 1)
            if popcnt(x) != popcnt(z):
                out_lines.append(f"{x} {y}")
                printed += 1
            x += 1
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

