let output = [];
function popcnt(x){
    // JavaScript numbers are 64‑bit floating, but N≤18 so safe as 32‑bit int
    let cnt = 0;
    while(x){
        cnt += x & 1;
        x >>>= 1;
    }
    return cnt;
}
